mapper.select:
SELECT 
FROM alarms a
JOIN plants p ON p.id = a.plant_id
LEFT JOIN facilities f ON f.id = a.facility_id

    AND a.plant_id = #{plantId}
    AND a.status = #{status}
    AND a.alarm_level = #{alarmLevel}

ORDER BY a.occurred_at DESC, a.id DESC
LIMIT #{limit}

mapper.delete:
DELETE FROM alarms
WHERE id = #{id}
  AND status = 'RESOLVED'

mapper.select:
SELECT COUNT(*)
FROM alarms
WHERE status = 'OCCURRED'
  AND plant_id = #{plantId}
  AND alarm_type = #{alarmType}
  AND occurred_at >= #{since}


          AND facility_id = #{facilityId}


          AND facility_id IS NULL
